import React, { useState } from 'react';
import axios from 'axios';
import './Contact.css';

const SERVICE_OPTIONS = [
  'Bookkeeping',
  'VAT Returns',
  'Payroll',
  'Year-End Accounts',
  'Corporation Tax',
  'Personal Tax Return',
  'Company Formation',
  'Management Accounts',
  'Tax Planning',
  'Business Advisory',
];

const initialFormState = {
  fullName: '',
  email: '',
  phone: '',
  preferredContactMethod: '',
  businessName: '',
  companyRegistrationNumber: '',
  businessType: '',
  annualRevenue: '',
  monthlyTransactions: '',
  vatRegistered: '',
  hasEmployees: '',
  employeeCount: '',
  accountingSoftware: '',
  servicesRequired: [],
  requirements: '',
};

const Contact = () => {
  const [formData, setFormData] = useState(initialFormState);
  const [status, setStatus] = useState({ type: '', message: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleServiceToggle = (label) => {
    setFormData((prev) => {
      const set = new Set(prev.servicesRequired);
      if (set.has(label)) set.delete(label);
      else set.add(label);
      return { ...prev, servicesRequired: [...set] };
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus({ type: '', message: '' });

    if (formData.servicesRequired.length === 0) {
      setStatus({
        type: 'error',
        message: 'Please select at least one service under Services Required.',
      });
      return;
    }

    if (formData.hasEmployees === 'yes') {
      const n = String(formData.employeeCount).trim();
      if (n === '' || Number.isNaN(Number(n)) || Number(n) < 0) {
        setStatus({
          type: 'error',
          message: 'Please enter how many employees you have.',
        });
        return;
      }
    }

    setIsSubmitting(true);

    try {
      const payload = {
        ...formData,
        employeeCount:
          formData.hasEmployees === 'yes' ? String(formData.employeeCount).trim() : '',
      };
      const response = await axios.post('/api/contact', payload);
      setSubmitted(true);
      setStatus({ type: 'success', message: response.data.message });
      setFormData(initialFormState);
    } catch (error) {
      setStatus({
        type: 'error',
        message: 'Something went wrong. Please try again.',
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="contact-page">
        <section className="contact-hero">
          <div className="container">
            <h1 className="page-title">Thank you</h1>
            <p className="page-subtitle">
              Thanks for your enquiry — the next step is to book a quick call so we can understand
              your needs and provide the best solution.
            </p>
          </div>
        </section>

        <section className="contact-content">
          <div className="container">
            <div className="contact-wrapper contact-wrapper--success">
              <div className="contact-form contact-success-card">
                <p className="contact-success-text">
                  Thanks for your enquiry — the next step is to book a quick call so we can understand
                  your needs and provide the best solution.
                </p>
                <a href="tel:+447428415130" className="btn-primary btn-large contact-success-cta">
                  Book a Free Consultation
                </a>
                <p className="contact-success-note">
                  Or email us at{' '}
                  <a href="mailto:Office@greylineaccountants.co.uk">Office@greylineaccountants.co.uk</a>
                </p>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }

  return (
    <div className="contact-page">
      <section className="contact-hero">
        <div className="container">
          <h1 className="page-title">Client enquiry</h1>
          <p className="page-subtitle">
            Tell us about your business and what you need — then book a free consultation with our
            team.
          </p>
        </div>
      </section>

      <section className="contact-content">
        <div className="container">
          <div className="contact-wrapper">
            <div className="contact-info">
              <h2>Contact Information</h2>
              <div className="info-item">
                <strong>Email:</strong>
                <p>
                  <a href="mailto:Office@greylineaccountants.co.uk">Office@greylineaccountants.co.uk</a>
                </p>
              </div>
              <div className="info-item">
                <strong>Phone:</strong>
                <p>
                  <a href="tel:+447428415130">+44 7428 415130</a>
                </p>
              </div>
              <div className="info-item">
                <strong>Office Hours:</strong>
                <p>Monday - Friday: 9:00 AM - 6:00 PM</p>
              </div>
              <div className="info-item">
                <strong>Address:</strong>
                <p>
                  5 HERMITAGE ROAD
                  <br />
                  WOKING
                  <br />
                  ENGLAND
                  <br />
                  GU21 8TE
                </p>
              </div>
            </div>

            <form className="contact-form" onSubmit={handleSubmit}>
              <h2>Book a Free Consultation</h2>

              <h3 className="form-section-title">1. Basic Information</h3>
              <div className="form-group">
                <label htmlFor="fullName">Full Name *</label>
                <input
                  type="text"
                  id="fullName"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleChange}
                  required
                  autoComplete="name"
                />
              </div>
              <div className="form-group">
                <label htmlFor="email">Email Address *</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  autoComplete="email"
                />
              </div>
              <div className="form-group">
                <label htmlFor="phone">Phone Number *</label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  required
                  autoComplete="tel"
                />
              </div>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Preferred Contact Method *</legend>
                <div className="form-options">
                  <label className="form-option">
                    <input
                      type="radio"
                      name="preferredContactMethod"
                      value="call"
                      checked={formData.preferredContactMethod === 'call'}
                      onChange={handleChange}
                      required
                    />
                    Call
                  </label>
                  <label className="form-option">
                    <input
                      type="radio"
                      name="preferredContactMethod"
                      value="whatsapp"
                      checked={formData.preferredContactMethod === 'whatsapp'}
                      onChange={handleChange}
                    />
                    WhatsApp
                  </label>
                  <label className="form-option">
                    <input
                      type="radio"
                      name="preferredContactMethod"
                      value="email"
                      checked={formData.preferredContactMethod === 'email'}
                      onChange={handleChange}
                    />
                    Email
                  </label>
                </div>
              </fieldset>

              <h3 className="form-section-title">2. Business Details</h3>
              <div className="form-group">
                <label htmlFor="businessName">Business Name *</label>
                <input
                  type="text"
                  id="businessName"
                  name="businessName"
                  value={formData.businessName}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label htmlFor="companyRegistrationNumber">Company Registration Number (optional)</label>
                <input
                  type="text"
                  id="companyRegistrationNumber"
                  name="companyRegistrationNumber"
                  value={formData.companyRegistrationNumber}
                  onChange={handleChange}
                />
              </div>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Business Type *</legend>
                <div className="form-options form-options--stack">
                  {[
                    ['limited_company', 'Limited Company'],
                    ['sole_trader', 'Sole Trader'],
                    ['partnership', 'Partnership'],
                    ['not_registered', 'Not yet registered'],
                  ].map(([value, label]) => (
                    <label key={value} className="form-option">
                      <input
                        type="radio"
                        name="businessType"
                        value={value}
                        checked={formData.businessType === value}
                        onChange={handleChange}
                        required
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>

              <h3 className="form-section-title">3. Financial Snapshot</h3>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Annual Revenue *</legend>
                <div className="form-options form-options--stack">
                  {[
                    ['0-50k', '£0 – £50k'],
                    ['50k-150k', '£50k – £150k'],
                    ['150k-500k', '£150k – £500k'],
                    ['500k-plus', '£500k+'],
                  ].map(([value, label]) => (
                    <label key={value} className="form-option">
                      <input
                        type="radio"
                        name="annualRevenue"
                        value={value}
                        checked={formData.annualRevenue === value}
                        onChange={handleChange}
                        required
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Number of Monthly Transactions *</legend>
                <div className="form-options">
                  {[
                    ['0-50', '0–50'],
                    ['50-200', '50–200'],
                    ['200-plus', '200+'],
                  ].map(([value, label]) => (
                    <label key={value} className="form-option">
                      <input
                        type="radio"
                        name="monthlyTransactions"
                        value={value}
                        checked={formData.monthlyTransactions === value}
                        onChange={handleChange}
                        required
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Are you VAT registered? *</legend>
                <div className="form-options">
                  {[
                    ['yes', 'Yes'],
                    ['no', 'No'],
                    ['not_sure', 'Not sure'],
                  ].map(([value, label]) => (
                    <label key={value} className="form-option">
                      <input
                        type="radio"
                        name="vatRegistered"
                        value={value}
                        checked={formData.vatRegistered === value}
                        onChange={handleChange}
                        required
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Do you have employees? *</legend>
                <div className="form-options form-options--stack">
                  <label className="form-option">
                    <input
                      type="radio"
                      name="hasEmployees"
                      value="yes"
                      checked={formData.hasEmployees === 'yes'}
                      onChange={handleChange}
                      required
                    />
                    Yes (number below)
                  </label>
                  {formData.hasEmployees === 'yes' && (
                    <div className="form-group form-group--nested">
                      <label htmlFor="employeeCount">Number of employees *</label>
                      <input
                        type="number"
                        id="employeeCount"
                        name="employeeCount"
                        min="0"
                        step="1"
                        value={formData.employeeCount}
                        onChange={handleChange}
                      />
                    </div>
                  )}
                  <label className="form-option">
                    <input
                      type="radio"
                      name="hasEmployees"
                      value="no"
                      checked={formData.hasEmployees === 'no'}
                      onChange={handleChange}
                    />
                    No
                  </label>
                </div>
              </fieldset>

              <h3 className="form-section-title">4. Accounting Setup</h3>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">What accounting software do you use? *</legend>
                <div className="form-options">
                  {[
                    ['xero', 'Xero'],
                    ['quickbooks', 'QuickBooks'],
                    ['excel', 'Excel'],
                    ['none', 'None'],
                  ].map(([value, label]) => (
                    <label key={value} className="form-option">
                      <input
                        type="radio"
                        name="accountingSoftware"
                        value={value}
                        checked={formData.accountingSoftware === value}
                        onChange={handleChange}
                        required
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>

              <h3 className="form-section-title">5. Services Required</h3>
              <fieldset className="form-group form-fieldset">
                <legend className="form-legend">Select all that apply *</legend>
                <div className="form-options form-options--stack">
                  {SERVICE_OPTIONS.map((label) => (
                    <label key={label} className="form-option">
                      <input
                        type="checkbox"
                        checked={formData.servicesRequired.includes(label)}
                        onChange={() => handleServiceToggle(label)}
                      />
                      {label}
                    </label>
                  ))}
                </div>
              </fieldset>

              <h3 className="form-section-title">6. Your Requirements</h3>
              <div className="form-group">
                <label htmlFor="requirements">
                  Briefly describe what you need help with or any challenges you&apos;re currently
                  facing *
                </label>
                <textarea
                  id="requirements"
                  name="requirements"
                  value={formData.requirements}
                  onChange={handleChange}
                  required
                  rows="5"
                />
              </div>

              {status.message && !submitted && (
                <div className={`form-status ${status.type}`}>{status.message}</div>
              )}

              <button type="submit" className="btn-primary btn-large" disabled={isSubmitting}>
                {isSubmitting ? 'Sending...' : 'Book a Free Consultation'}
              </button>
            </form>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Contact;
